+    public static void testUnslice(VectorSpecies s1, int part) {
+        TestMethod op = () -> {
+            var v = s1.zero();
+            return v.unslice(1, v, part);
+        };
+
+        if (0 <= part && part <= 1) {
+            expectSuccess(op);
+        } else {
+            String msg = String.format("bad part number %d for slice operation", part);
+            expectAIOOBE(op, msg);
+        }
+    }
